        cdef unsigned int h2 = (((val * 2246822519) & 0xFFFFFFFF) ^ (val >> 13)) & 0xFFFFFFFF
        for j in range(k):
            pos = ((h1 + j * h2) & 0xFFFFFFFF) % m
            bits[pos] = 1

    # Count bits set
    for i in range(m):
        bits_set += bits[i]

    # Probe: test values 0..2*n-1
