        cdef unsigned int h2 = (((i * 2246822519) & 0xFFFFFFFF) ^ (i >> 13)) & 0xFFFFFFFF
        for j in range(k):
            pos = ((h1 + j * h2) & 0xFFFFFFFF) % m
